    public void test_computeCompletenessComplex() throws Exception {
      initTestNodes();
      runWithinCommand(() -> {
        // <> means "manually mapped"
        //                                    comp
        //                                    /  \
        //                        FC4_in_compl    <FC2_in_compl>
        //                         /      \                 \
        //            <FC2_in_FC4>     FC2_2_in_FC4         FC5_in_FC2
        //            /                     \
        //      FC5_in_FC2                <FC5_in_FC2>


        Tree fromMappingContainer = Tree.initFunctionTree(getAnnotatedNode("complexCompleteMapping"));
        AbstractTreeRoot actualTreeRoot = fromMappingContainer.getRoot();

        // the whole instance is completelly mapped, cause all subnodes indirectly mapped

        // first is mapped
        TreeNode comp = as_i40jd0_a0a61a0a1a6p(ListSequence.fromList(actualTreeRoot.getChildren()).first(), TreeNode.class);
        Assert.assertTrue(comp.isMapped());
        // FC2_in_comp
        TreeNode FC4_in_compl = as_i40jd0_a0a91a0a1a6p(ListSequence.fromList(comp.getChildren()).getElement(0), TreeNode.class);
        Assert.assertTrue(FC4_in_compl.isMapped());
        TreeNode FC2_in_compl = as_i40jd0_a0a12a0a1a6p(ListSequence.fromList(comp.getChildren()).getElement(1), TreeNode.class);
        Assert.assertTrue(FC2_in_compl.isMapped());
        // root mapped
        Assert.assertTrue(actualTreeRoot.isMapped());

      });
    }
